import{_ as a,o as e,c as l,ag as n}from"./chunks/framework.-Wrcbzkw.js";const c=JSON.parse('{"title":"图解 TCP/IP","description":"","frontmatter":{},"headers":[],"relativePath":"notes/图解TCPIP.md","filePath":"notes/图解TCPIP.md","lastUpdated":1777674309000}'),s={name:"notes/图解TCPIP.md"};function i(r,t,d,o,p,h){return e(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="图解-tcp-ip" tabindex="-1">图解 TCP/IP <a class="header-anchor" href="#图解-tcp-ip" aria-label="Permalink to &quot;图解 TCP/IP&quot;">​</a></h1><h2 id="第一章-网络基础知识" tabindex="-1">第一章：网络基础知识 <a class="header-anchor" href="#第一章-网络基础知识" aria-label="Permalink to &quot;第一章：网络基础知识&quot;">​</a></h2><h3 id="_1-1-osi-参考模型" tabindex="-1">1.1 OSI 参考模型 <a class="header-anchor" href="#_1-1-osi-参考模型" aria-label="Permalink to &quot;1.1 OSI 参考模型&quot;">​</a></h3><p>计算机网络中，<strong>接口</strong>和<strong>协议</strong>是两个核心概念：</p><ul><li><strong>接口</strong>：上下层之间进行交互时所遵循的约定</li><li><strong>协议</strong>：同一层之间进行交互时所遵循的约定</li></ul><h4 id="osi-七层模型" tabindex="-1">OSI 七层模型 <a class="header-anchor" href="#osi-七层模型" aria-label="Permalink to &quot;OSI 七层模型&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">名称</th><th style="text-align:left;">主要功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>7</strong></td><td style="text-align:left;">应用层</td><td style="text-align:left;">为应用程序提供网络服务（HTTP、FTP、DNS）</td></tr><tr><td style="text-align:left;"><strong>6</strong></td><td style="text-align:left;">表示层</td><td style="text-align:left;">数据格式转换、加密解密、压缩解压</td></tr><tr><td style="text-align:left;"><strong>5</strong></td><td style="text-align:left;">会话层</td><td style="text-align:left;">建立、管理和终止表示层实体之间的通信会话</td></tr><tr><td style="text-align:left;"><strong>4</strong></td><td style="text-align:left;">传输层</td><td style="text-align:left;">端到端的数据传输（TCP、UDP）</td></tr><tr><td style="text-align:left;"><strong>3</strong></td><td style="text-align:left;">网络层</td><td style="text-align:left;">路由选择和分组转发（IP）</td></tr><tr><td style="text-align:left;"><strong>2</strong></td><td style="text-align:left;">数据链路层</td><td style="text-align:left;">物理地址寻址、帧同步、差错检测</td></tr><tr><td style="text-align:left;"><strong>1</strong></td><td style="text-align:left;">物理层</td><td style="text-align:left;">物理介质上的信号传输（网线、光纤、无线电）</td></tr></tbody></table><h4 id="数据封装过程" tabindex="-1">数据封装过程 <a class="header-anchor" href="#数据封装过程" aria-label="Permalink to &quot;数据封装过程&quot;">​</a></h4><p>当数据从应用层向下传输时，每一层都会添加自己的头部信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用层数据</span></span>
<span class="line"><span>    ↓ 添加应用层头部</span></span>
<span class="line"><span>应用层协议数据单元 (APDU)</span></span>
<span class="line"><span>    ↓ 添加表示层头部</span></span>
<span class="line"><span>表示层协议数据单元 (PPDU)</span></span>
<span class="line"><span>    ↓ 添加会话层头部</span></span>
<span class="line"><span>会话层协议数据单元 (SPDU)</span></span>
<span class="line"><span>    ↓ 添加传输层头部</span></span>
<span class="line"><span>传输层协议数据单元 (Segment / Datagram)</span></span>
<span class="line"><span>    ↓ 添加网络层头部</span></span>
<span class="line"><span>网络层协议数据单元 (Packet)</span></span>
<span class="line"><span>    ↓ 添加数据链路层头部和尾部</span></span>
<span class="line"><span>数据链路层协议数据单元 (Frame)</span></span>
<span class="line"><span>    ↓ 转换为物理信号</span></span>
<span class="line"><span>物理层传输</span></span></code></pre></div><h3 id="_1-2-计算机网络分类" tabindex="-1">1.2 计算机网络分类 <a class="header-anchor" href="#_1-2-计算机网络分类" aria-label="Permalink to &quot;1.2 计算机网络分类&quot;">​</a></h3><p>根据覆盖范围，计算机网络可分为：</p><h4 id="局域网-lan-local-area-network" tabindex="-1">局域网 (LAN - Local Area Network) <a class="header-anchor" href="#局域网-lan-local-area-network" aria-label="Permalink to &quot;局域网 (LAN - Local Area Network)&quot;">​</a></h4><ul><li><strong>覆盖范围</strong>：较小地理范围（如办公室、学校、家庭）</li><li><strong>特点</strong>：高速、低延迟、成本低</li><li><strong>典型技术</strong>：以太网、Wi-Fi</li></ul><h4 id="广域网-wan-wide-area-network" tabindex="-1">广域网 (WAN - Wide Area Network) <a class="header-anchor" href="#广域网-wan-wide-area-network" aria-label="Permalink to &quot;广域网 (WAN - Wide Area Network)&quot;">​</a></h4><ul><li><strong>覆盖范围</strong>：较大地理范围（城市、国家、全球）</li><li><strong>特点</strong>：覆盖广、可能经过多个网络设备</li><li><strong>典型技术</strong>：光纤、卫星通信、VPN</li></ul><h4 id="城域网-man-metropolitan-area-network" tabindex="-1">城域网 (MAN - Metropolitan Area Network) <a class="header-anchor" href="#城域网-man-metropolitan-area-network" aria-label="Permalink to &quot;城域网 (MAN - Metropolitan Area Network)&quot;">​</a></h4><ul><li><strong>覆盖范围</strong>：介于局域网和广域网之间（城市范围）</li><li><strong>用途</strong>：连接多个局域网</li></ul><hr><h2 id="第二章-tcp-ip-协议族" tabindex="-1">第二章：TCP/IP 协议族 <a class="header-anchor" href="#第二章-tcp-ip-协议族" aria-label="Permalink to &quot;第二章：TCP/IP 协议族&quot;">​</a></h2><h3 id="_2-1-tcp-ip-四层模型" tabindex="-1">2.1 TCP/IP 四层模型 <a class="header-anchor" href="#_2-1-tcp-ip-四层模型" aria-label="Permalink to &quot;2.1 TCP/IP 四层模型&quot;">​</a></h3><p>TCP/IP 协议族简化了 OSI 模型，将其分为四层：</p><table tabindex="0"><thead><tr><th style="text-align:left;">TCP/IP 层</th><th style="text-align:left;">对应 OSI 层</th><th style="text-align:left;">主要协议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>应用层</strong></td><td style="text-align:left;">应用层 + 表示层 + 会话层</td><td style="text-align:left;">HTTP、HTTPS、FTP、SMTP、DNS</td></tr><tr><td style="text-align:left;"><strong>传输层</strong></td><td style="text-align:left;">传输层</td><td style="text-align:left;">TCP、UDP</td></tr><tr><td style="text-align:left;"><strong>网络层</strong></td><td style="text-align:left;">网络层</td><td style="text-align:left;">IP、ICMP、ARP、RARP</td></tr><tr><td style="text-align:left;"><strong>网络接口层</strong></td><td style="text-align:left;">数据链路层 + 物理层</td><td style="text-align:left;">以太网、Wi-Fi、PPP</td></tr></tbody></table><h3 id="_2-2-ip-协议" tabindex="-1">2.2 IP 协议 <a class="header-anchor" href="#_2-2-ip-协议" aria-label="Permalink to &quot;2.2 IP 协议&quot;">​</a></h3><h4 id="ip-地址" tabindex="-1">IP 地址 <a class="header-anchor" href="#ip-地址" aria-label="Permalink to &quot;IP 地址&quot;">​</a></h4><p>IP 地址用于标识网络中的主机，分为 IPv4 和 IPv6：</p><p><strong>IPv4 地址</strong>：32 位二进制数，通常表示为点分十进制（如 <code>192.168.1.1</code>）</p><p><strong>IPv6 地址</strong>：128 位二进制数，通常表示为冒号分隔的十六进制（如 <code>2001:0db8:85a3:0000:0000:8a2e:0370:7334</code>）</p><h4 id="ip-地址分类-ipv4" tabindex="-1">IP 地址分类（IPv4） <a class="header-anchor" href="#ip-地址分类-ipv4" aria-label="Permalink to &quot;IP 地址分类（IPv4）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">范围</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">A</td><td style="text-align:left;">1.0.0.0 - 126.255.255.255</td><td style="text-align:left;">大型网络</td></tr><tr><td style="text-align:left;">B</td><td style="text-align:left;">128.0.0.0 - 191.255.255.255</td><td style="text-align:left;">中型网络</td></tr><tr><td style="text-align:left;">C</td><td style="text-align:left;">192.0.0.0 - 223.255.255.255</td><td style="text-align:left;">小型网络</td></tr><tr><td style="text-align:left;">D</td><td style="text-align:left;">224.0.0.0 - 239.255.255.255</td><td style="text-align:left;">多播</td></tr><tr><td style="text-align:left;">E</td><td style="text-align:left;">240.0.0.0 - 255.255.255.255</td><td style="text-align:left;">保留</td></tr></tbody></table><h4 id="私有-ip-地址" tabindex="-1">私有 IP 地址 <a class="header-anchor" href="#私有-ip-地址" aria-label="Permalink to &quot;私有 IP 地址&quot;">​</a></h4><p>用于局域网内部，不会在互联网上路由：</p><ul><li>A 类：<code>10.0.0.0 - 10.255.255.255</code></li><li>B 类：<code>172.16.0.0 - 172.31.255.255</code></li><li>C 类：<code>192.168.0.0 - 192.168.255.255</code></li></ul><h3 id="_2-3-tcp-协议" tabindex="-1">2.3 TCP 协议 <a class="header-anchor" href="#_2-3-tcp-协议" aria-label="Permalink to &quot;2.3 TCP 协议&quot;">​</a></h3><h4 id="tcp-特点" tabindex="-1">TCP 特点 <a class="header-anchor" href="#tcp-特点" aria-label="Permalink to &quot;TCP 特点&quot;">​</a></h4><ul><li><strong>面向连接</strong>：建立连接 → 数据传输 → 断开连接</li><li><strong>可靠传输</strong>：确认、重传、流量控制、拥塞控制</li><li><strong>有序交付</strong>：按顺序传递数据</li><li><strong>面向字节流</strong>：无边界的字节序列</li></ul><h4 id="tcp-三次握手" tabindex="-1">TCP 三次握手 <a class="header-anchor" href="#tcp-三次握手" aria-label="Permalink to &quot;TCP 三次握手&quot;">​</a></h4><p>建立连接的过程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端                    服务器</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  SYN (seq=x)             │</span></span>
<span class="line"><span>  │─────────────────────────&gt;│</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  SYN+ACK (seq=y, ack=x+1)│</span></span>
<span class="line"><span>  │&lt;─────────────────────────│</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  ACK (ack=y+1)           │</span></span>
<span class="line"><span>  │─────────────────────────&gt;│</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │      连接建立成功        │</span></span></code></pre></div><h4 id="tcp-四次挥手" tabindex="-1">TCP 四次挥手 <a class="header-anchor" href="#tcp-四次挥手" aria-label="Permalink to &quot;TCP 四次挥手&quot;">​</a></h4><p>断开连接的过程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端                    服务器</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  FIN (seq=x)             │</span></span>
<span class="line"><span>  │─────────────────────────&gt;│  客户端不再发送数据</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  ACK (ack=x+1)           │</span></span>
<span class="line"><span>  │&lt;─────────────────────────│  服务器确认收到</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  FIN (seq=y)             │</span></span>
<span class="line"><span>  │&lt;─────────────────────────│  服务器不再发送数据</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │  ACK (ack=y+1)           │</span></span>
<span class="line"><span>  │─────────────────────────&gt;│  客户端确认收到</span></span>
<span class="line"><span>  │                          │</span></span>
<span class="line"><span>  │      连接断开成功        │</span></span></code></pre></div><h4 id="tcp-滑动窗口" tabindex="-1">TCP 滑动窗口 <a class="header-anchor" href="#tcp-滑动窗口" aria-label="Permalink to &quot;TCP 滑动窗口&quot;">​</a></h4><p>用于流量控制，提高传输效率：</p><ul><li><strong>发送窗口</strong>：允许发送但尚未确认的数据范围</li><li><strong>接收窗口</strong>：接收方当前能接收的数据量</li><li><strong>拥塞窗口</strong>：根据网络拥塞情况动态调整</li></ul><h3 id="_2-4-udp-协议" tabindex="-1">2.4 UDP 协议 <a class="header-anchor" href="#_2-4-udp-协议" aria-label="Permalink to &quot;2.4 UDP 协议&quot;">​</a></h3><h4 id="udp-特点" tabindex="-1">UDP 特点 <a class="header-anchor" href="#udp-特点" aria-label="Permalink to &quot;UDP 特点&quot;">​</a></h4><ul><li><strong>无连接</strong>：不需要建立连接</li><li><strong>不可靠传输</strong>：不保证数据到达，不保证顺序</li><li><strong>面向报文</strong>：保留消息边界</li><li><strong>开销小</strong>：头部只有 8 字节</li></ul><h4 id="udp-vs-tcp" tabindex="-1">UDP vs TCP <a class="header-anchor" href="#udp-vs-tcp" aria-label="Permalink to &quot;UDP vs TCP&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">TCP</th><th style="text-align:left;">UDP</th></tr></thead><tbody><tr><td style="text-align:left;">连接</td><td style="text-align:left;">面向连接</td><td style="text-align:left;">无连接</td></tr><tr><td style="text-align:left;">可靠性</td><td style="text-align:left;">可靠（重传、确认）</td><td style="text-align:left;">不可靠</td></tr><tr><td style="text-align:left;">顺序</td><td style="text-align:left;">保证顺序</td><td style="text-align:left;">不保证顺序</td></tr><tr><td style="text-align:left;">速度</td><td style="text-align:left;">较慢</td><td style="text-align:left;">较快</td></tr><tr><td style="text-align:left;">开销</td><td style="text-align:left;">较大（20-60 字节头部）</td><td style="text-align:left;">较小（8 字节头部）</td></tr><tr><td style="text-align:left;">适用场景</td><td style="text-align:left;">文件传输、网页浏览</td><td style="text-align:left;">实时视频、音频、游戏</td></tr></tbody></table><hr><h2 id="第三章-常用应用层协议" tabindex="-1">第三章：常用应用层协议 <a class="header-anchor" href="#第三章-常用应用层协议" aria-label="Permalink to &quot;第三章：常用应用层协议&quot;">​</a></h2><h3 id="_3-1-http-协议" tabindex="-1">3.1 HTTP 协议 <a class="header-anchor" href="#_3-1-http-协议" aria-label="Permalink to &quot;3.1 HTTP 协议&quot;">​</a></h3><h4 id="http-请求方法" tabindex="-1">HTTP 请求方法 <a class="header-anchor" href="#http-请求方法" aria-label="Permalink to &quot;HTTP 请求方法&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;">GET</td><td style="text-align:left;">请求获取资源</td></tr><tr><td style="text-align:left;">POST</td><td style="text-align:left;">提交数据到服务器</td></tr><tr><td style="text-align:left;">PUT</td><td style="text-align:left;">更新资源</td></tr><tr><td style="text-align:left;">DELETE</td><td style="text-align:left;">删除资源</td></tr><tr><td style="text-align:left;">HEAD</td><td style="text-align:left;">获取资源头部信息</td></tr><tr><td style="text-align:left;">OPTIONS</td><td style="text-align:left;">获取服务器支持的方法</td></tr></tbody></table><h4 id="http-状态码" tabindex="-1">HTTP 状态码 <a class="header-anchor" href="#http-状态码" aria-label="Permalink to &quot;HTTP 状态码&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">状态码</th><th style="text-align:left;">类别</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">1xx</td><td style="text-align:left;">信息性</td><td style="text-align:left;">请求已接收，继续处理</td></tr><tr><td style="text-align:left;">2xx</td><td style="text-align:left;">成功</td><td style="text-align:left;">请求成功处理</td></tr><tr><td style="text-align:left;">3xx</td><td style="text-align:left;">重定向</td><td style="text-align:left;">需要进一步操作</td></tr><tr><td style="text-align:left;">4xx</td><td style="text-align:left;">客户端错误</td><td style="text-align:left;">请求有误</td></tr><tr><td style="text-align:left;">5xx</td><td style="text-align:left;">服务器错误</td><td style="text-align:left;">服务器处理失败</td></tr></tbody></table><h3 id="_3-2-https-协议" tabindex="-1">3.2 HTTPS 协议 <a class="header-anchor" href="#_3-2-https-协议" aria-label="Permalink to &quot;3.2 HTTPS 协议&quot;">​</a></h3><p>在 HTTP 基础上加入 SSL/TLS 加密：</p><ul><li><strong>加密方式</strong>：非对称加密（握手）+ 对称加密（数据传输）</li><li><strong>证书验证</strong>：通过 CA 证书验证服务器身份</li><li><strong>端口</strong>：默认 443</li></ul><h3 id="_3-3-dns-协议" tabindex="-1">3.3 DNS 协议 <a class="header-anchor" href="#_3-3-dns-协议" aria-label="Permalink to &quot;3.3 DNS 协议&quot;">​</a></h3><p>域名系统（Domain Name System）：</p><ul><li><strong>功能</strong>：将域名转换为 IP 地址</li><li><strong>查询方式</strong>：递归查询、迭代查询</li><li><strong>记录类型</strong>：A、AAAA、CNAME、MX、TXT</li></ul><hr><h2 id="第四章-网络层辅助协议" tabindex="-1">第四章：网络层辅助协议 <a class="header-anchor" href="#第四章-网络层辅助协议" aria-label="Permalink to &quot;第四章：网络层辅助协议&quot;">​</a></h2><h3 id="_4-1-arp-协议" tabindex="-1">4.1 ARP 协议 <a class="header-anchor" href="#_4-1-arp-协议" aria-label="Permalink to &quot;4.1 ARP 协议&quot;">​</a></h3><p>地址解析协议（Address Resolution Protocol）：</p><ul><li><strong>功能</strong>：将 IP 地址转换为 MAC 地址</li><li><strong>工作方式</strong>：广播请求，单播响应</li></ul><h3 id="_4-2-icmp-协议" tabindex="-1">4.2 ICMP 协议 <a class="header-anchor" href="#_4-2-icmp-协议" aria-label="Permalink to &quot;4.2 ICMP 协议&quot;">​</a></h3><p>互联网控制消息协议（Internet Control Message Protocol）：</p><ul><li><strong>功能</strong>：传递控制消息和错误报告</li><li><strong>常见应用</strong>：ping 命令</li></ul><h3 id="_4-3-dhcp-协议" tabindex="-1">4.3 DHCP 协议 <a class="header-anchor" href="#_4-3-dhcp-协议" aria-label="Permalink to &quot;4.3 DHCP 协议&quot;">​</a></h3><p>动态主机配置协议（Dynamic Host Configuration Protocol）：</p><ul><li><strong>功能</strong>：自动分配 IP 地址、子网掩码、网关、DNS 服务器</li><li><strong>过程</strong>：发现 → 提供 → 请求 → 确认</li></ul><hr><h2 id="第五章-网络设备" tabindex="-1">第五章：网络设备 <a class="header-anchor" href="#第五章-网络设备" aria-label="Permalink to &quot;第五章：网络设备&quot;">​</a></h2><h3 id="_5-1-交换机-switch" tabindex="-1">5.1 交换机 (Switch) <a class="header-anchor" href="#_5-1-交换机-switch" aria-label="Permalink to &quot;5.1 交换机 (Switch)&quot;">​</a></h3><ul><li><strong>工作层次</strong>：数据链路层</li><li><strong>功能</strong>：基于 MAC 地址转发帧</li><li><strong>特点</strong>：分割冲突域，不分割广播域</li></ul><h3 id="_5-2-路由器-router" tabindex="-1">5.2 路由器 (Router) <a class="header-anchor" href="#_5-2-路由器-router" aria-label="Permalink to &quot;5.2 路由器 (Router)&quot;">​</a></h3><ul><li><strong>工作层次</strong>：网络层</li><li><strong>功能</strong>：基于 IP 地址转发数据包</li><li><strong>特点</strong>：分割广播域，实现不同网络之间的通信</li></ul><h3 id="_5-3-网关-gateway" tabindex="-1">5.3 网关 (Gateway) <a class="header-anchor" href="#_5-3-网关-gateway" aria-label="Permalink to &quot;5.3 网关 (Gateway)&quot;">​</a></h3><ul><li><strong>功能</strong>：连接不同协议的网络</li><li><strong>作用</strong>：协议转换、数据格式转换</li></ul><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>TCP/IP 协议族是互联网的基石，理解其分层结构和各层协议的作用，对于深入理解网络通信原理至关重要：</p><ol><li><strong>分层设计</strong>：每层有明确的职责，通过接口与上下层交互</li><li><strong>协议栈</strong>：从应用层到物理层，数据逐层封装后传输</li><li><strong>核心协议</strong>：IP 负责寻址，TCP 负责可靠传输，UDP 负责快速传输</li><li><strong>辅助协议</strong>：ARP、ICMP、DHCP 等协议协助完成网络通信</li></ol><p>掌握这些基础知识，是学习网络编程、网络安全、系统架构的重要基础。</p>`,87)])])}const x=a(s,[["render",i]]);export{c as __pageData,x as default};
